# tools/standard_tool_schema.py
# Blueprint standard: tool names use snake_case, descriptions start with a verb,
# parameters use snake_case, all parameters have descriptions.

KNOWLEDGE_BASE_SEARCH = {
    "name": "search_knowledge_base",
    "description": "Search the knowledge base for documents relevant to a query. "
                   "Use this when the user asks about a topic that may be covered "
                   "in the product documentation or policy library.",
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {
                "type": "string",
                "description": "The search query, expressed as a natural language question "
                               "or a set of keywords relevant to the topic."
            },
            "max_results": {
                "type": "integer",
                "description": "Maximum number of documents to return. Defaults to 5.",
                "default": 5,
                "minimum": 1,
                "maximum": 20
            }
        },
        "required": ["query"]
    }
}

ESCALATE_TO_HUMAN = {
    "name": "escalate_to_human",
    "description": "Escalate the conversation to a human agent. Use this when the user's "
                   "request cannot be answered from the knowledge base, the user expresses "
                   "frustration, or the topic is outside the integration's scope.",
    "input_schema": {
        "type": "object",
        "properties": {
            "reason": {
                "type": "string",
                "description": "Brief explanation of why escalation is needed."
            },
            "priority": {
                "type": "string",
                "enum": ["normal", "urgent"],
                "description": "Escalation priority."
            }
        },
        "required": ["reason", "priority"]
    }
}

# context/budget.py
from dataclasses import dataclass

@dataclass(frozen=True)
class ContextBudget:
    # All values in tokens. These are the blueprint-mandated defaults.
    # A deployment can set tighter limits but not looser ones without review.
    system_prompt_max: int = 2_000
    retrieved_context_max: int = 8_000   # per RAG retrieval pass
    conversation_history_max: int = 4_000
    user_message_max: int = 2_000
    response_reservation: int = 1_024   # reserved for Claude's output
    safety_margin: int = 500

    @property
    def total_input_budget(self) -> int:
        return (
            self.system_prompt_max
            + self.retrieved_context_max
            + self.conversation_history_max
            + self.user_message_max
        )

    @property
    def model_context_window(self) -> int:
        return self.total_input_budget + self.response_reservation + self.safety_margin

# Standard budget for claude-sonnet-4-6 deployments
STANDARD_BUDGET = ContextBudget()

def validate_prompt_fits_budget(
    system_tokens: int,
    context_tokens: int,
    history_tokens: int,
    user_tokens: int,
    budget: ContextBudget = STANDARD_BUDGET,
) -> None:
    errors = []
    if system_tokens > budget.system_prompt_max:
        errors.append(f"system_prompt: {system_tokens} > {budget.system_prompt_max}")
    if context_tokens > budget.retrieved_context_max:
        errors.append(f"retrieved_context: {context_tokens} > {budget.retrieved_context_max}")
    if history_tokens > budget.conversation_history_max:
        errors.append(f"history: {history_tokens} > {budget.conversation_history_max}")
    if user_tokens > budget.user_message_max:
        errors.append(f"user_message: {user_tokens} > {budget.user_message_max}")
    if errors:
        raise ValueError(f"Context budget exceeded: {'; '.join(errors)}")
